fn popcount(n: i64) -> i64 = {
    let mut count: i64 = 0;
    let mut x: i64 = n;
    while x > 0 {
        set count = count + (x band 1);
        set x = x >> 1;
    };
    count
};

fn main() -> i64 = {
    let t: i64 = read_int();
